SELECT CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1 OR b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) < :param_2) THEN DATEFROMPARTS(YEAR(lk.lk_referral_date), MONTH(lk.lk_referral_date), 1) ELSE NULL END AS event_month, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) < :param_2) THEN :param_3 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) > :param_4) THEN :param_5 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) < :param_6) THEN :param_7 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1) THEN DATEDIFF(day, lk.lk_referral_date, b.loaded_at) ELSE NULL END AS lag_day, CAST(b.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR(max)) AS batch_id, CAST(NULL AS VARCHAR(max)) AS alt_value, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1) THEN :param_8 ELSE :param_9 END AS is_eligible, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NULL) THEN :param_10 ELSE :param_11 END AS is_null_event_time, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NULL) THEN :param_12 ELSE :param_13 END AS is_null_load_time_only, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_14 AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) < :param_15) THEN :param_16 ELSE :param_17 END AS is_negative_clipped, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) < :param_2) THEN :param_18 ELSE :param_19 END AS is_negative_lag_excluded, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) >= :param_1 AND DATEDIFF(day, lk.lk_referral_date, b.loaded_at) > :param_20) THEN :param_21 ELSE :param_22 END AS is_overflow, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NULL) THEN :param_23 ELSE :param_24 END AS is_join_unmatched, CASE WHEN (b.mp_base_marker IS NOT NULL AND (lk.lk_matched IS NULL OR lk.lk_rn = :lk_rn_1)) THEN :param_25 ELSE :param_26 END AS is_base_row, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_rn = :lk_rn_2 AND lk.lk_dup > :lk_dup_1) THEN :param_27 ELSE :param_28 END AS is_ambiguous_base, CAST(:param_29 AS INTEGER) AS is_compare_mismatch, CASE WHEN (b.mp_base_marker IS NOT NULL) THEN :param_30 ELSE :param_31 END AS is_probe_row, lk.lk_dup AS lookup_dup, CAST(NULL AS VARCHAR(max)) AS key_hash, b.loaded_at AS load_time  INTO #mp_probe 
FROM (SELECT demo_health.dbo.episodes.loaded_at AS loaded_at, demo_health.dbo.episodes.referral_id AS referral_id, demo_health.dbo.episodes.site_code AS site_code, :param_32 AS mp_base_marker 
FROM demo_health.dbo.episodes) AS b FULL OUTER JOIN (SELECT demo_health.dbo.referrals.id AS lk_id, demo_health.dbo.referrals.referral_date AS lk_referral_date, demo_health.dbo.referrals.site AS lk_site, :param_33 AS lk_matched, count(*) OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_dup, row_number() OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site ORDER BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_rn 
FROM demo_health.dbo.referrals) AS lk ON b.referral_id = lk.lk_id AND b.site_code = lk.lk_site 
WHERE b.loaded_at <= :as_of OR b.loaded_at IS NULL
